## Testing Requirements

### Unit Tests

```rust
#[cfg(test)]
mod tests {
    use super::*;
    use tracing_test::traced_test;

    #[test]
    fn test_default_is_empty() {
        let s = Style::default();
        assert!(s.is_empty());
        assert_eq!(s.fg, None);
        assert_eq!(s.bg, None);
        assert_eq!(s.attrs, None);
    }

    #[test]
    fn test_builder_pattern() {
        let s = Style::new()
            .fg(PackedRgba::RED)
            .bg(PackedRgba::BLACK)
            .bold()
            .underline();

        assert_eq!(s.fg, Some(PackedRgba::RED));
        assert_eq!(s.bg, Some(PackedRgba::BLACK));
        assert!(s.has_attr(StyleFlags::BOLD));
        assert!(s.has_attr(StyleFlags::UNDERLINE));
    }

    #[traced_test]
    #[test]
    fn test_merge_child_wins() {
        let parent = Style::new().fg(PackedRgba::RED);
        let child = Style::new().fg(PackedRgba::BLUE);
        let merged = child.merge(&parent);

        assert_eq!(merged.fg, Some(PackedRgba::BLUE)); // Child wins
        assert!(logs_contain("Merging child into parent"));
    }

    #[test]
    fn test_merge_parent_fills() {
        let parent = Style::new().fg(PackedRgba::RED).bg(PackedRgba::WHITE);
        let child = Style::new().fg(PackedRgba::BLUE); // No bg
        let merged = child.merge(&parent);

        assert_eq!(merged.fg, Some(PackedRgba::BLUE)); // Child fg
        assert_eq!(merged.bg, Some(PackedRgba::WHITE)); // Parent fills bg
    }

    #[test]
    fn test_merge_attrs_combine() {
        let parent = Style::new().bold();
        let child = Style::new().italic();
        let merged = child.merge(&parent);

        assert!(merged.has_attr(StyleFlags::BOLD)); // From parent
        assert!(merged.has_attr(StyleFlags::ITALIC)); // From child
    }

    #[test]
    fn test_patch_is_symmetric() {
        let parent = Style::new().fg(PackedRgba::RED);
        let child = Style::new().bg(PackedRgba::BLUE);

        let merged1 = child.merge(&parent);
        let merged2 = parent.patch(&child);

        assert_eq!(merged1, merged2);
    }

    #[test]
    fn test_style_flags_operations() {
        let mut flags = StyleFlags::NONE;
        flags.insert(StyleFlags::BOLD);
        flags.insert(StyleFlags::ITALIC);

        assert!(flags.contains(StyleFlags::BOLD));
        assert!(flags.contains(StyleFlags::ITALIC));
        assert!(!flags.contains(StyleFlags::UNDERLINE));

        flags.remove(StyleFlags::BOLD);
        assert!(!flags.contains(StyleFlags::BOLD));
        assert!(flags.contains(StyleFlags::ITALIC));
    }
}
